"use client";
import React from 'react';
import styled from 'styled-components';
import Button from "../../../components/button/js/Button.jsx";

const BlogSectionContainer = styled.section`
  padding: 0;
  margin-bottom: 60px;
  
  @media (max-width: 768px) {
    margin-bottom: 40px;
    padding: 0;
  }
  
  @media (max-width: 480px) {
    margin-bottom: 30px;
    padding: 0;
  }
`;

const ContentWrapper = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
  
  @media (max-width: 768px) {
    padding: 0 16px;
  }
  
  @media (max-width: 480px) {
    padding: 0 12px;
  }
`;

const SectionHeader = styled.div`
  text-align: center;
  margin-bottom: 30px;
  
  @media (max-width: 768px) {
    margin-bottom: 40px;
  }
`;

const SectionTitle = styled.h2`
  margin-bottom: 15px;
  color: #1a1a1a;
  @media (max-width: 768px) {
    margin-bottom: 12px;
  }
  @media (max-width: 480px) {
    margin-bottom: 10px;
  }
`;

const BlogGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  grid-template-rows: repeat(3, 1fr);
  gap: 15px;
  margin-bottom: 60px;
  
  @media (max-width: 1200px) {
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: auto;
  }
  
  @media (max-width: 992px) {
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: auto;
  }
  
  @media (max-width: 576px) {
    grid-template-columns: repeat(2, 1fr);
    grid-template-rows: auto;
    gap: 12px;
    margin-bottom: 32px;
  }
  
  @media (max-width: 480px) {
    grid-template-columns: repeat(2, 1fr);
    gap: 8px;
    margin-bottom: 24px;
  }
`;

const BlogCard = styled.div`
  overflow: hidden;
  padding: 20px;
  text-align: center;
  
  @media (max-width: 768px) {
    padding: 14px;
  }
  @media (max-width: 576px) {
    padding: 10px;
    max-width: 180px;
    margin: 0 auto;
  }
  @media (max-width: 480px) {
    padding: 8px;
    max-width: 150px;
    margin: 0 auto;
  }
`;

const BlogImage = styled.div`
  overflow: hidden;
  margin: 0 auto 12px;
  
  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
  }
  
  ${BlogCard}:hover & img {
    transform: scale(1.05);
  }
`;

const BlogTitle = styled.h3`
  margin: 0;
  line-height: 1.4;
  color: #1a1a1a;
  text-align: center;
`;

