const BlogSection = () => {
  return (
    <BlogSectionContainer>
      <ContentWrapper>
        <SectionHeader>
          <SectionTitle className='universal-fs-h8 universal-font-bold'>
            End-to-end interior solutions
          </SectionTitle>
        </SectionHeader>

        <BlogGrid>
          {blogPosts.map(post => (
            <BlogCard key={post.id}>
              <BlogImage>
                {post.image}
                {/* <img src={post.image} alt={post.title} loading="lazy" /> */}
              </BlogImage>
              <BlogTitle className='universal-fs-h3'>{post.title}</BlogTitle>
            </BlogCard>
          ))}
        </BlogGrid>

        <div style={{ textAlign: "center" }}>
          {/* <Button primary>Book Free Design Session</Button> */}

        </div>
      </ContentWrapper>
    </BlogSectionContainer>
  );
};

export default BlogSection;

